import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: 'warning' | 'error' | 'success' | 'info';
}

const NotificationContext = createContext(null);

export const useNotificationContext = () => {
  const notificationElement = useContext(NotificationContext);
  const [notification, setNotification] = useState(null);

  useEffect(() => {
    if (notificationElement) {
      const handleNotification = async (props: NotificationProps) => {
        try {
          const { heading, subheading, type } = props;
          await notificationElement.open({
            heading,
            subheading,
            type,
          });
        } catch (error) {
          console.error(error);
        }
      };
      setNotification(handleNotification);
    }
  }, [notificationElement]);

  return notification;
};

export default NotificationContext;
```

